def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio > 1:
            priorities[i] = np.inf
            continue
        score = 0
        for j in range(1, 11):
            threshold = j * 0.1
            if ratio < threshold:
                score += (11 - j) * 0.3
            else:
                score -= j * 0.05
            if j % 2 == 0 and ratio < threshold / 2:
                score += 0.2 * j
            elif j % 3 == 0 and ratio > threshold * 0.8:
                score -= 0.15 * j
        if capacity % 3 == 0:
            score *= 1.2
            if item % 2 == 0:
                score += 0.5
            else:
                score -= 0.3
        elif capacity % 5 == 0:
            score *= 0.85
            if item > capacity / 2:
                score -= 0.7
            else:
                score += 0.4
        else:
            if item < capacity * 0.3:
                score *= 1.05
            else:
                score *= 0.95
        if score < 0:
            score = 0
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        max_priority = 0
    else:
        max_priority = np.max(finite_priorities)
    for i in range(len(priorities)):
        if not np.isfinite(priorities[i]):
            priorities[i] = max_priority + 15
    return priorities
